#include<bits/stdc++.h>
using namespace std;
bool prime(int x){
    if(x!=2&&x!=1) for(int i=2;i<x;i++){if(x%i==0) return false;}
    return true;
}
bool pl(int x){
    int a,i=1;
    string b,c;
    a=x;
    c=x;
    b+=char(a%10+'0');
    a/=10;
    while(a!=0){
        b+=char(a%10+'0');
        a/=10;
        i++;
    }
    //cout<<b;
    //cout<<c;
    for(int j=0;j<i;j++){
        if(b[j]!=c[j]) return false;
    }
    return true;
}
int main(){
    int a,b;
    cin>>a>>b;
    if(a%2==0)a++;
    for(int i=a;i<=b;i+=2){
        if(pl(i)&&prime(i)){
            cout<<i<<endl;
        }
    }
}
